INSERT INTO `products` VALUES (4,'ASUS','Laptop','ASUS Vivobook 15 X1504VA i5 1335U 16GB 512GB là mẫu laptop ASUS phù hợp cho học tập, làm việc, giải trí và xử lý đa nhiệm. Sản phẩm có thiết kế hiện đại, cấu hình cân bằng, dung lượng lưu trữ tốt và trải nghiệm sử dụng ổn định cho nhu cầu hằng ngày.','[{\"icon\":\"⚡\",\"title\":\"Hiệu năng ổn định\",\"description\":\"Đáp ứng tốt học tập, văn phòng và giải trí hằng ngày\"},{\"icon\":\"?\",\"title\":\"Pin linh hoạt\",\"description\":\"Phù hợp làm việc di động trong nhiều giờ\"},{\"icon\":\"?\",\"title\":\"Màn hình sắc nét\",\"description\":\"Không gian hiển thị rộng, màu sắc dễ nhìn\"},{\"icon\":\"?\",\"title\":\"SSD nhanh\",\"description\":\"Mở máy, truy cập file và chạy ứng dụng nhanh hơn\"},{\"icon\":\"⭐\",\"title\":\"Thiết kế hiện đại\",\"description\":\"Ngoại hình gọn gàng, dễ mang theo khi đi học hoặc đi làm\"}]','http://localhost:8080/uploads/b025a001-509f-4a08-8448-85c6a1a88a08.webp','ASUS Vivobook 15 X1504VA i5 1335U 16GB 512GB','[{\"groupName\":\"RAM\",\"values\":[{\"name\":\"16GB\",\"price\":15490000},{\"name\":\"32GB\",\"price\":17990000}]},{\"groupName\":\"Ổ cứng\",\"values\":[{\"name\":\"512GB SSD\",\"price\":15490000},{\"name\":\"1TB SSD\",\"price\":17290000}]},{\"groupName\":\"Màu sắc\",\"values\":[{\"name\":\"Bạc\",\"price\":15490000},{\"name\":\"Đen\",\"price\":15490000}]},{\"groupName\":\"Bảo hành\",\"values\":[{\"name\":\"12 tháng chính hãng\",\"price\":15490000},{\"name\":\"24 tháng mở rộng\",\"price\":16690000}]}]',15490000.00,'[{\"icon\":\"?\",\"title\":\"Trả góp 0%\",\"description\":\"Hỗ trợ trả góp qua thẻ tín dụng và công ty tài chính\"},{\"icon\":\"?\",\"title\":\"Miễn phí giao hàng\",\"description\":\"Giao hàng miễn phí trong khu vực áp dụng\"},{\"icon\":\"?\",\"title\":\"Tặng balo laptop\",\"description\":\"Tặng kèm balo ElectroShop khi mua sản phẩm\"},{\"icon\":\"?\",\"title\":\"Hỗ trợ cài đặt\",\"description\":\"Hỗ trợ cài phần mềm cơ bản và kiểm tra máy trước khi giao\"}]','[{\"key\":\"CPU\",\"value\":\"Intel Core i5 1335U\"},{\"key\":\"RAM\",\"value\":\"16GB\"},{\"key\":\"Ổ cứng\",\"value\":\"512GB SSD\"},{\"key\":\"VGA\",\"value\":\"Intel Iris Xe\"},{\"key\":\"Màn hình\",\"value\":\"15.6 inch Full HD IPS\"},{\"key\":\"Tần số quét\",\"value\":\"60Hz\"},{\"key\":\"Bàn phím\",\"value\":\"Có đèn nền\"},{\"key\":\"Cổng kết nối\",\"value\":\"USB-A, USB-C, HDMI, jack tai nghe, khe sạc\"},{\"key\":\"Pin\",\"value\":\"3 cell đến 4 cell, tối ưu cho học tập và làm việc\"},{\"key\":\"Hệ điều hành\",\"value\":\"Windows 11 Home\"},{\"key\":\"Trọng lượng\",\"value\":\"1.70 kg\"},{\"key\":\"Màu sắc\",\"value\":\"Bạc\"}]',13,1),(5,'ASUS','Laptop','ASUS Vivobook 16 X1605ZA i5 1235U 16GB 512GB là mẫu laptop ASUS phù hợp cho học tập, làm việc, giải trí và xử lý đa nhiệm. Sản phẩm có thiết kế hiện đại, cấu hình cân bằng, dung lượng lưu trữ tốt và trải nghiệm sử dụng ổn định cho nhu cầu hằng ngày.','[{\"icon\":\"⚡\",\"title\":\"Hiệu năng ổn định\",\"description\":\"Đáp ứng tốt học tập, văn phòng và giải trí hằng ngày\"},{\"icon\":\"?\",\"title\":\"Pin linh hoạt\",\"description\":\"Phù hợp làm việc di động trong nhiều giờ\"},{\"icon\":\"?\",\"title\":\"Màn hình sắc nét\",\"description\":\"Không gian hiển thị rộng, màu sắc dễ nhìn\"},{\"icon\":\"?\",\"title\":\"SSD nhanh\",\"description\":\"Mở máy, truy cập file và chạy ứng dụng nhanh hơn\"},{\"icon\":\"⭐\",\"title\":\"Thiết kế hiện đại\",\"description\":\"Ngoại hình gọn gàng, dễ mang theo khi đi học hoặc đi làm\"}]','https://cdnv2.tgdd.vn/mwg-static/tgdd/Products/Images/44/364397/asus-vivobook-16-a1607qa-x1-26-100-mb067w-1-639094284869406469.jpg','ASUS Vivobook 16 X1605ZA i5 1235U 16GB 512GB','[{\"groupName\":\"RAM\",\"values\":[{\"name\":\"16GB\",\"price\":16990000},{\"name\":\"32GB\",\"price\":19490000}]},{\"groupName\":\"Ổ cứng\",\"values\":[{\"name\":\"512GB SSD\",\"price\":16990000},{\"name\":\"1TB SSD\",\"price\":18790000}]},{\"groupName\":\"Màu sắc\",\"values\":[{\"name\":\"Đen\",\"price\":16990000},{\"name\":\"